INSERT INTO `room` VALUES (1,'Modern Home',1,1,'AVAILABLE','https://alloggio.qodeinteractive.com/wp-content/uploads/2020/03/h1-room-img-04.jpg',550000.00,'Không gian hiện đại, thiết kế tối giản nhưng đầy đủ tiện nghi, phù hợp cho những ai yêu thích sự tinh tế và thoải mái.'),(2,'Casa Mancini',1,1,'AVAILABLE','https://alloggio.qodeinteractive.com/wp-content/uploads/2020/03/room-featured-img-06.jpg',550000.00,'Phòng mang phong cách Ý sang trọng, ấm cúng với nội thất tinh xảo, đem lại cảm giác thư giãn và đẳng cấp.'),(3,'Bright Suite',2,2,'AVAILABLE','https://alloggio.qodeinteractive.com/wp-content/uploads/2020/03/room-featured-img-01.jpg',850000.00,'Căn phòng tràn ngập ánh sáng tự nhiên, rộng rãi và thoáng đãng, lý tưởng cho kỳ nghỉ nhẹ nhàng và dễ chịu.'),(4,'Sea Home',2,2,'AVAILABLE','https://alloggio.qodeinteractive.com/wp-content/uploads/2020/03/room-single-gallery-img-15.jpg',850000.00,'Không gian hướng biển mát mẻ, thiết kế gần gũi thiên nhiên, mang lại trải nghiệm nghỉ dưỡng thư thái.'),(5,'House Ciardi',3,5,'AVAILABLE','https://alloggio.qodeinteractive.com/wp-content/uploads/2020/03/room-featured-img-10.jpg',1250000.00,'Phòng mang phong cách cổ điển pha chút hiện đại, ấm áp và riêng tư, phù hợp cho những ai tìm kiếm sự yên bình.'),(69,'Sofitel Metropole Luxury Room',4,3,'AVAILABLE','https://d2e5ushqwiltxm.cloudfront.net/wp-content/uploads/sites/95/2024/01/24043542/DSC03899.jpg',2800000.00,'Inspired by Sofitel Legend Metropole Hanoi Heritage Wing.'),(70,'Sofitel Metropole Grand Luxury',4,4,'AVAILABLE','https://d2e5ushqwiltxm.cloudfront.net/wp-content/uploads/sites/95/2024/01/24044332/DSC05618.jpg',3300000.00,'Colonial Indochine style with hardwood floor and refined lighting.'),(71,'Sofitel Metropole Suite',5,5,'AVAILABLE','https://d2e5ushqwiltxm.cloudfront.net/wp-content/uploads/sites/95/2024/01/24044356/DSC05868.jpg',5200000.00,'Suite with separate sitting area inspired by Metropole Hanoi.'),(72,'Caravelle Saigon Deluxe',4,12,'AVAILABLE','https://www.caravellehotel.com/wp-content/uploads/Caravelle-Saigon-Deluxe-rooms.jpg',2400000.00,'Inspired by Caravelle Saigon Deluxe rooms near Lam Son Square.'),(73,'Caravelle Saigon Opera',4,14,'AVAILABLE','https://www.caravellehotel.com/wp-content/uploads/Caravelle-Saigon-Opera-Rooms-1.jpg',2900000.00,'Soundproof windows with Opera House inspired city view.'),(74,'Caravelle Executive Suite',5,17,'CLEANING','https://www.caravellehotel.com/wp-content/uploads/Caravelle-Saigon-Executive-Suite-1.jpg',4800000.00,'Executive suite with separate living room and business amenities.'),(75,'Caravelle Opera View Suite',5,18,'AVAILABLE','https://www.caravellehotel.com/wp-content/uploads/Caravelle-Saigon-Opera-View-Suite-03-scaled.jpg',5600000.00,'Large suite with balcony and Opera House inspired view.'),(76,'The Reverie Deluxe King',4,28,'AVAILABLE','https://www.thereveriesaigon.com/wp-content/uploads/2021/11/Deluxe-King-Room-Urban-View-Luxury-in-Ho-Chi-Minh-City-The-Reverie-Saigon-2000x1334.jpg',3900000.00,'Inspired by The Reverie Saigon Deluxe Room with urban view.'),(77,'The Reverie Grand Deluxe Twin',4,31,'OCCUPIED','https://www.thereveriesaigon.com/wp-content/uploads/2021/11/Grand-Deluxe-Twin-Room-Urban-View-Luxury-in-Ho-Chi-Minh-City-The-Reverie-Saigon-2000x1334.jpg',4300000.00,'Grand Deluxe twin room inspired by Italian decor and skyline views.'),(78,'The Reverie Panorama Deluxe',4,34,'AVAILABLE','https://www.thereveriesaigon.com/wp-content/uploads/2021/11/Panorama-Deluxe-Room-Urban-View-Luxury-in-Ho-Chi-Minh-City-The-Reverie-Saigon-2000x1334.jpg',5000000.00,'Panorama room with wrap-around windows and city or river view.'),(79,'The Reverie Designer Suite',8,36,'AVAILABLE','https://www.thereveriesaigon.com/wp-content/uploads/2021/11/Designer-Suite-by-Provasi_1920x1080_.jpg',11800000.00,'Designer suite inspired by The Reverie Saigon luxury suite collection.'),(80,'Six Senses Hill Top Pool Villa',6,1,'AVAILABLE','https://media.sixsenses.com/B60H3R33/at/g85fs6mcsj3bsfnq2csrr4m4/1_Hill_Top_Pool_Villa-aerial.jpg?fit=crop&format=webp&height=405&width=648',8200000.00,'Hill top pool villa inspired by Six Senses Ninh Van Bay.'),(81,'Six Senses Beachfront Pool Villa',6,1,'AVAILABLE','https://media.sixsenses.com/B60H3R33/at/7zb69v8w29nhcmtw59bkmrk5/1_Beachfront_Pool_Villa-aerial.jpg?fit=crop&format=webp&height=405&width=648',8700000.00,'Beachfront villa with private plunge pool and direct beach access.'),(82,'Six Senses Rock Pool Villa',6,2,'MAINTENANCE','https://media.sixsenses.com/B60H3R33/at/9bx7v5rhbqg96nv2w6pxgsq/1_Rock_Pool_Villa_aerial.jpg?fit=crop&format=webp&height=405&width=648',9400000.00,'Rock pool villa set among coastal rock formations.'),(83,'Six Senses Water Pool Villa',6,2,'AVAILABLE','https://media.sixsenses.com/B60H3R33/at/9h272hxvs8b3vjhp9k86kjpm/Water_Pool_Villa_bathroom.jpg?fit=crop&format=webp&height=405&width=648',9800000.00,'Water edge villa with ocean access and private deck.'),(84,'Six Senses Family Beach Villa',7,1,'AVAILABLE','https://media.sixsenses.com/B60H3R33/at/gn9bsg6vpv6v3fjtq7wsxjn/Family_Beach_Pool_Villa.jpg?fit=crop&format=webp&height=405&width=648',12800000.00,'Family beach pool villa with two bedrooms and generous living space.'),(85,'La Siesta Premium Terrace',5,4,'AVAILABLE','https://lasiestahoianresort.com/wp-content/uploads/2021/06/Premium-Suite-with-Terrace-Club-Wing-4.jpg',3600000.00,'Inspired by La Siesta Hoi An Premium Suite with Terrace.'),(86,'La Siesta Duplex Suite',7,5,'AVAILABLE','https://lasiestahoianresort.com/wp-content/uploads/2021/06/Duplex-Suite-Club-Wing-5.jpg',4200000.00,'Duplex suite inspired by La Siesta Hoi An Club Wing.');
