INSERT INTO `room_type` VALUES (1,'Standard Single',1,'Phòng đơn tiêu chuẩn, đầy đủ tiện nghi cơ bản',1),(2,'Deluxe Double',2,'Phòng đôi cao cấp, hướng biển, có ban công',1),(3,'VIP Suite',4,'Phòng hạng sang, phòng khách riêng, bồn tắm nằm',1),(4,'Luxury City Room',2,'Phong hang sang huong thanh pho, phu hop khach cong tac va nghi duong.',1),(5,'Heritage Suite',3,'Suite lay cam hung tu cac khach san lich su voi phong khach rieng.',1),(6,'Beach Pool Villa',3,'Villa nghi duong bien co ho boi rieng va khong gian ngoai troi.',1),(7,'Family Suite',5,'Phong gia dinh nhieu giuong, dien tich lon, thuan tien cho ky nghi dai ngay.',1),(8,'Presidential Suite',4,'Suite cao cap voi phong khach lon, tam nhin dep va dich vu uu tien.',1);
