INSERT INTO `services` VALUES (2,'Dọn phòng',300000.00,'Tính theo kg đồ thường',1),(3,'Đưa đón',400000.00,'Dịch vụ xe riêng tiện lợi, đặt lịch trước để đảm bảo đúng giờ.',1),(4,'Ẩm thực cá nhân',900000.00,'Bữa ăn riêng tư với thực đơn chọn sẵn, phục vụ tại phòng hoặc nhà hàng.',1),(5,'Ẩm thực couple',1700000.00,'Không gian lãng mạn với set menu đặc biệt, phù hợp cho những dịp đặc biệt.',1),(6,'Spa Signature',650000.00,'Massage thu gian va cham soc co the tai spa.',1),(7,'Buffet Sang',350000.00,'Buffet sang tai nha hang khach san.',1),(8,'Giat ui nhanh',180000.00,'Giat ui trong ngay cho khach luu tru.',1),(9,'Trang tri phong',750000.00,'Trang tri phong cho ky niem, sinh nhat hoac cau hon.',1),(10,'Tour thanh pho',1200000.00,'Tour nua ngay tham quan diem den noi bat.',1),(11,'Late checkout',500000.00,'Gia han tra phong theo gio khi con phong trong.',1),(12,'Xe limousine san bay',900000.00,'Xe rieng dua don san bay theo lich dat truoc.',1);
